/// Trait for partial projection operations (subset of components)
pub trait PartialProject: Project {
    /// Project data onto a subset of components
    /// 
    /// # Arguments
    /// * `data` - Input data matrix
    /// * `component_indices` - Indices of components to project onto
    /// 
    /// # Returns
    /// Projected data using only specified components
    fn project_components(
        &self, 
        data: &Matrix, 
        component_indices: &[usize]
    ) -> Result<Matrix, MultivariousError>;

    /// Get the importance/variance explained by each component
    fn component_importance(&self) -> Result<Vector, MultivariousError>;

    /// Select top k components by importance
    fn select_top_components(&self, k: usize) -> Result<Vec<usize>, MultivariousError> {
        let importance = self.component_importance()?;
        let mut indices: Vec<usize> = (0..importance.len()).collect();
        indices.sort_by(|&a, &b| {
            importance[b].partial_cmp(&importance[a]).unwrap_or(std::cmp::Ordering::Equal)
        });
        Ok(indices.into_iter().take(k).collect())
    }
}

/// Trait for transposing projection models
pub trait Transpose: Project {
    /// Type of the transposed model
    type Transposed: Project;

    /// Create a transposed version of the projector
    /// 
    /// This is useful for switching between projecting samples vs features
    fn transpose(&self) -> Result<Self::Transposed, MultivariousError>;
}

