impl BiProjector {
    /// Create a new BiProjector
    pub fn new(
        v: BaseProjector,
        s: Matrix,
        singular_values: Vector,
        n_features: usize,
        name: String,
    ) -> Self {
        Self { v, s, singular_values, n_features, name }
    }

    /// Builder pattern for creating BiProjector
    pub fn builder() -> BiProjectorBuilder {
        BiProjectorBuilder::new()
    }

    /// Get explained variance from singular values
    pub fn explained_variance(&self) -> Vector {
        let total: f64 = self.singular_values.iter().map(|&x| x * x).sum();
        self.singular_values.mapv(|x| (x * x) / total)
    }

    /// Get cumulative explained variance
    pub fn cumulative_variance(&self) -> Vector {
        let var_ratio = self.explained_variance();
        let mut cumulative = Vector::zeros(var_ratio.len());
        let mut sum = 0.0;
        for i in 0..var_ratio.len() {
            sum += var_ratio[i];
            cumulative[i] = sum;
        }
        cumulative
    }

    /// Get scores matrix (sample projections)
    pub fn scores(&self) -> &Matrix {
        &self.s
    }

    /// Get components matrix (variable loadings)
    pub fn components(&self) -> Result<&Matrix, MultivariousError> {
        Ok(self.v.projection_matrix())
    }

    /// Get standard deviations (singular values)
    pub fn sdev(&self) -> &Vector {
        &self.singular_values
    }

    /// Compute residuals for given data
    /// Residuals = X - X_reconstructed
    pub fn residuals(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        // Project and then reconstruct
        let projected = self.project(data)?;
        let reconstructed = self.reconstruct(&projected)?;

        // Compute residuals
        Ok(data - &reconstructed)
    }

    /// Get singular values
    pub fn singular_values(&self) -> &Vector {
        &self.singular_values
    }
}

