     1→use crate::common_types::{Matrix, Vector};
     2→use crate::errors::MultivariousError;
     3→use crate::projector::traits::{Project, ProjectorConfig, Reconstruct, PartialProject, Transpose};
     4→use crate::projector::base::BaseProjector;
     5→use crate::validation::check_dimensions_match;
     6→use ndarray::{Array1, Array2};
     7→use serde::{Deserialize, Serialize};
     8→
     9→/// Bidirectional projector for methods that project both samples and variables
    10→///
    11→/// This is the base structure for dimensionality reduction methods like PCA, PLS, etc.
    12→/// that compute projections for both observations (scores) and variables (loadings).
    13→#[derive(Debug, Clone, Serialize, Deserialize)]
    14→pub struct BiProjector {
    15→    /// Base projector for sample projection (loadings matrix)
    16→    pub v: BaseProjector,
    17→    
    18→    /// Singular values or component standard deviations
    19→    pub s: Vector,
    20→    
    21→    /// Standard deviations of components (often sqrt of eigenvalues)
    22→    pub sdev: Vector,
    23→    
    24→    /// Number of samples used in fitting
    25→    n_samples: usize,
    26→    
    27→    /// Number of features
    28→    n_features: usize,
    29→    
    30→    /// Name of the biprojector
    31→    name: String,
    32→}
    33→
    34→impl BiProjector {
    35→    /// Create a new BiProjector
    36→    ///
    37→    /// # Arguments
    38→    /// * `loadings` - The loadings matrix (features × components)
    39→    /// * `s` - Singular values or component variances
    40→    /// * `n_samples` - Number of samples used in fitting
    41→    /// * `config` - Projector configuration
    42→    pub fn new(
    43→        loadings: Matrix,
    44→        s: Vector,
    45→        n_samples: usize,
    46→        config: ProjectorConfig,
    47→    ) -> Result<Self, MultivariousError> {
    48→        // Validate dimensions
    49→        if loadings.ncols() != s.len() {
    50→            return Err(MultivariousError::DimensionMismatch {
    51→                expected: format!("loadings columns ({})", loadings.ncols()),
    52→                actual: format!("singular values length ({})", s.len()),
    53→            });
    54→        }
    55→        
    56→        // Create base projector from loadings
    57→        let v = BaseProjector::new(loadings.clone(), config)?;
    58→        
    59→        // Compute standard deviations
    60→        // For PCA: sdev = sqrt(eigenvalues) = s / sqrt(n_samples - 1)
    61→        let sdev = if n_samples > 1 {
    62→            &s / (n_samples as f64 - 1.0).sqrt()
    63→        } else {
    64→            s.clone()
    65→        };
    66→        
    67→        Ok(Self {
    68→            v,
    69→            s,
    70→            sdev,
    71→            n_samples,
    72→            n_features: loadings.nrows(),
    73→            name: "BiProjector".to_string(),
    74→        })
    75→    }
    76→    
    77→    /// Get the loadings matrix (V)
    78→    pub fn loadings(&self) -> &Matrix {
    79→        self.v.projection_matrix()
    80→    }
    81→    
    82→    /// Get singular values
    83→    pub fn singular_values(&self) -> &Vector {
    84→        &self.s
    85→    }
    86→    
    87→    /// Get standard deviations
    88→    pub fn standard_deviations(&self) -> &Vector {
    89→        &self.sdev
    90→    }
    91→    
    92→    /// Project variables (transpose projection)
    93→    ///
    94→    /// For PCA, this projects the variables into the component space
    95→    /// Result is the correlation/covariance between variables and components
    96→    pub fn project_vars(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
    97→        // For variables projection: data^T * scores / n
    98→        // But we can use the fact that scores = data * loadings
    99→        // So: data^T * data * loadings / n = correlation matrix * loadings
   100→        
   101→        check_dimensions_match(
   102→            data.ncols(),
   103→            self.n_features,
   104→            "data features",
   105→            "projector features"
   106→        )?;
   107→        
   108→        // Compute correlation/covariance matrix
   109→        let data_t = data.t();
   110→        let cov_matrix = data_t.dot(data) / (self.n_samples as f64);
   111→        
   112→        // Project: cov * loadings
   113→        Ok(cov_matrix.dot(self.loadings()))
   114→    }
   115→    
   116→    /// Compute scores from data
   117→    ///
   118→    /// This is equivalent to project() but emphasizes that we're computing
   119→    /// sample scores in the component space
   120→    pub fn scores(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   121→        self.v.project(data)
   122→    }
   123→    
   124→    /// Set the name of the projector
   125→    pub fn set_name(&mut self, name: String) {
   126→        self.name = name;
   127→    }
   128→    
   129→    /// Get explained variance for each component
   130→    ///
   131→    /// Returns the variance explained by each component
   132→    pub fn explained_variance(&self) -> Vector {
   133→        // Variance = sdev^2
   134→        self.sdev.mapv(|x| x * x)
   135→    }
   136→    
   137→    /// Get the proportion of variance explained by each component
   138→    ///
   139→    /// Requires total variance to be provided (usually computed during fitting)
   140→    pub fn explained_variance_ratio(&self, total_variance: f64) -> Vector {
   141→        if total_variance > 0.0 {
   142→            self.explained_variance() / total_variance
   143→        } else {
   144→            Vector::zeros(self.sdev.len())
   145→        }
   146→    }
   147→}
