    fn test_transpose() {
        let loadings = generate_orthogonal_matrix(5, 3);
        let s = Array1::from_vec(vec![3.0, 2.0, 1.0]);

        let projector = BiProjector::new(
            loadings.clone(),
            s,
            10,
            ProjectorConfig::default()
        ).unwrap();

        let transposed = projector.transpose().unwrap();

        // Transposed projector should have dimensions flipped
        assert_eq!(transposed.n_components(), 5); // Original features
        assert_eq!(transposed.n_features(), 3);   // Original components

        // The projection matrix should be the transpose of loadings
        let expected = loadings.t();
        assert_eq!(transposed.projection_matrix().shape(), expected.shape());
    }
}

