use crate::common_types::{Matrix, Vector};
use crate::errors::MultivariousError;
use crate::projector::traits::{Project, ProjectorConfig, Reconstruct, PartialProject, Transpose};
use crate::projector::base::BaseProjector;
use crate::validation::check_dimensions_match;
use ndarray::{Array1, Array2};
use serde::{Deserialize, Serialize};

/// Bidirectional projector for methods that project both samples and variables
///
/// This is the base structure for dimensionality reduction methods like PCA, PLS, etc.
/// that compute projections for both observations (scores) and variables (loadings).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BiProjector {
    /// Base projector for sample projection (loadings matrix)
    pub v: BaseProjector,

    /// Singular values or component standard deviations
    pub s: Vector,

    /// Standard deviations of components (often sqrt of eigenvalues)
    pub sdev: Vector,

    /// Number of samples used in fitting
    n_samples: usize,

    /// Number of features
    n_features: usize,

    /// Name of the biprojector
    name: String,
}

impl BiProjector {
    /// Create a new BiProjector
    ///
    /// # Arguments
    /// * `loadings` - The loadings matrix (features × components)
    /// * `s` - Singular values or component variances
    /// * `n_samples` - Number of samples used in fitting
    /// * `config` - Projector configuration
    pub fn new(
        loadings: Matrix,
        s: Vector,
        n_samples: usize,
        config: ProjectorConfig,
    ) -> Result<Self, MultivariousError> {
        // Validate dimensions
        if loadings.ncols() != s.len() {
            return Err(MultivariousError::DimensionMismatch {
                expected: format!("loadings columns ({})", loadings.ncols()),
                actual: format!("singular values length ({})", s.len()),
            });
        }

        // Create base projector from loadings
        let v = BaseProjector::new(loadings.clone(), config)?;

        // Compute standard deviations
        // For PCA: sdev = sqrt(eigenvalues) = s / sqrt(n_samples - 1)
        let sdev = if n_samples > 1 {
            &s / (n_samples as f64 - 1.0).sqrt()
        } else {
            s.clone()
        };

        Ok(Self {
            v,
            s,
            sdev,
            n_samples,
            n_features: loadings.nrows(),
            name: "BiProjector".to_string(),
        })
    }

    /// Get the loadings matrix (V)
    pub fn loadings(&self) -> &Matrix {
        self.v.projection_matrix()
    }

    /// Get singular values
    pub fn singular_values(&self) -> &Vector {
        &self.s
    }

    /// Get standard deviations
    pub fn standard_deviations(&self) -> &Vector {
        &self.sdev
    }

    /// Project variables (transpose projection)
    ///
    /// For PCA, this projects the variables into the component space
    /// Result is the correlation/covariance between variables and components
    pub fn project_vars(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        // For variables projection: data^T * scores / n
        // But we can use the fact that scores = data * loadings
        // So: data^T * data * loadings / n = correlation matrix * loadings

        check_dimensions_match(
            data.ncols(),
            self.n_features,
            "data features",
            "projector features"
        )?;

        // Compute correlation/covariance matrix
        let data_t = data.t();
        let cov_matrix = data_t.dot(data) / (self.n_samples as f64);

        // Project: cov * loadings
        Ok(cov_matrix.dot(self.loadings()))
    }

    /// Compute scores from data
    ///
    /// This is equivalent to project() but emphasizes that we're computing
    /// sample scores in the component space
    pub fn scores(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.v.project(data)
    }

    /// Set the name of the projector
    pub fn set_name(&mut self, name: String) {
        self.name = name;
    }

    /// Get explained variance for each component
    ///
    /// Returns the variance explained by each component
    pub fn explained_variance(&self) -> Vector {
        // Variance = sdev^2
        self.sdev.mapv(|x| x * x)
    }

    /// Get the proportion of variance explained by each component
    ///
    /// Requires total variance to be provided (usually computed during fitting)
    pub fn explained_variance_ratio(&self, total_variance: f64) -> Vector {
        if total_variance > 0.0 {
            self.explained_variance() / total_variance
        } else {
            Vector::zeros(self.sdev.len())
        }
    }

    /// Get components (alias for loadings)
    pub fn components(&self) -> &Matrix {
        self.loadings()
    }

    /// Get standard deviations (alias for standard_deviations)
    pub fn sdev(&self) -> &Vector {
        self.standard_deviations()
    }

    /// Compute residuals for given data
    /// Residuals = X - X_reconstructed
    pub fn residuals(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        // Project and then reconstruct
        let projected = self.project(data)?;
        let reconstructed = self.reconstruct(&projected)?;

        // Compute residuals
        Ok(data - &reconstructed)
    }
}

// Implement the Project trait by delegating to the base projector
impl Project for BiProjector {
    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.v.project(data)
    }

    fn n_components(&self) -> usize {
        self.v.n_components()
    }

    fn n_features(&self) -> usize {
        self.n_features
    }

    fn is_fitted(&self) -> bool {
        self.v.is_fitted()
    }

    fn name(&self) -> &str {
        &self.name
    }
}

// Implement Reconstruct trait by delegating to base projector
impl Reconstruct for BiProjector {
    fn reconstruct(&self, projected: &Matrix) -> Result<Matrix, MultivariousError> {
        self.v.reconstruct(projected)
    }
}

// Implement PartialProject trait
impl PartialProject for BiProjector {
    fn project_components(&self, data: &Matrix, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
        self.v.project_components(data, component_indices)
    }

    fn component_importance(&self) -> Result<Vector, MultivariousError> {
        // For biprojector, importance is based on explained variance
        Ok(self.explained_variance())
    }
}

// Implement Transpose trait for variable projection
impl Transpose for BiProjector {
    type Transposed = BaseProjector;

    fn transpose(&self) -> Result<Self::Transposed, MultivariousError> {
        // Create a transposed projector that projects variables instead of samples
        // For PCA and similar methods, the transposed projector uses the scores (S) matrix
        // to project variables into the sample space

        // Get the scores matrix by projecting the identity-like matrix
        // This is a simplification; in practice, we'd need the original data
        // or store the scores during fitting

        // For now, we'll create a projector using the loadings transposed
        // This allows projecting from component space to variable space
        let loadings_t = self.loadings().t().to_owned();

        // Create a new BaseProjector with transposed loadings
        let config = ProjectorConfig::default();
        BaseProjector::new(loadings_t, config)
    }
}

/// Builder for BiProjector
#[derive(Debug, Clone)]
pub struct BiProjectorBuilder {
    loadings: Option<Matrix>,
    s: Option<Vector>,
    n_samples: Option<usize>,
    config: ProjectorConfig,
    name: String,
}

impl BiProjectorBuilder {
    pub fn new() -> Self {
        Self {
            loadings: None,
            s: None,
            n_samples: None,
            config: ProjectorConfig::default(),
            name: "BiProjector".to_string(),
        }
    }

    pub fn loadings(mut self, loadings: Matrix) -> Self {
        self.loadings = Some(loadings);
        self
    }

    pub fn singular_values(mut self, s: Vector) -> Self {
        self.s = Some(s);
        self
    }

    pub fn n_samples(mut self, n: usize) -> Self {
        self.n_samples = Some(n);
        self
    }

    pub fn config(mut self, config: ProjectorConfig) -> Self {
        self.config = config;
        self
    }

    pub fn name(mut self, name: String) -> Self {
        self.name = name;
        self
    }

    pub fn build(self) -> Result<BiProjector, MultivariousError> {
        let loadings = self.loadings.ok_or_else(|| MultivariousError::InvalidParameter {
            name: "loadings".to_string(),
            value: "None".to_string(),
            reason: "loadings matrix is required".to_string(),
        })?;

        let s = self.s.ok_or_else(|| MultivariousError::InvalidParameter {
            name: "singular_values".to_string(),
            value: "None".to_string(),
            reason: "singular values are required".to_string(),
        })?;

        let n_samples = self.n_samples.ok_or_else(|| MultivariousError::InvalidParameter {
            name: "n_samples".to_string(),
            value: "None".to_string(),
            reason: "number of samples is required".to_string(),
        })?;

        let mut projector = BiProjector::new(loadings, s, n_samples, self.config)?;
        projector.set_name(self.name);
        Ok(projector)
    }
}

impl Default for BiProjectorBuilder {
    fn default() -> Self {
        Self::new()
    }
}

